class Solution {
public:
    int countNumbers(string l, string r, int b) {
        int res = 0;
        for (int i = stoi(l); i <= stoi(r); i++) {
            string s = to_string(i);
            bool flag = true;
            for (int j = 0; j < s.length() - 1; j++) {
                if (stoi(string(1, s[j])) > stoi(string(1, s[j + 1]))) {
                    flag = false;
                    break;
                }
            }
            if (flag) res = (res + 1) % (1e9 + 7);
        }
        return res;
    }
};
```
